mapper.select:
SELECT pr.id, pr.user_id as user_id, u.username, u.avatar as avatar, pr.rating, pr.content, pr.created_at as created_at, pr.review_images as review_images, p.title as productTitle, pi.url as productMainImage FROM product_review pr LEFT JOIN user u ON pr.user_id = u.id LEFT JOIN product p ON pr.product_id = p.id LEFT JOIN product_image pi ON p.id = pi.product_id AND pi.image_type = 0 WHERE p.saller_id = #{sellerId}
AND pr.created_at >= #{startDate}
ORDER BY pr.created_at DESC
